import React from "react";
import { useState } from "react";
import "./../styles/Sidebar.css";

const Sidebar = ({ role }) => {
  const commonLinks = [
    { name: "Dashboard", path: "/" },
    { name: "Borrow/Return", path: "/borrow-return" },
  ];

  const adminLinks = [
    { name: "Books Management", path: "/books" },
    { name: "Users Management", path: "/users" },
  ];

  return (
    <div className="sidebar">
      <div className="sidebar-title">Library System</div>
      <ul>
        {commonLinks.map((link, index) => (
          <li key={index}>{link.name}</li>
        ))}
        {role === "admin" &&
          adminLinks.map((link, index) => <li key={index}>{link.name}</li>)}
        <li>Logout</li>
      </ul>
    </div>
  );
};

export default Sidebar;
